    def stream_csv(self, file_path: str) -> Iterator[pd.DataFrame]:
        """Stream CSV file in chunks to avoid memory issues"""
        try:
            for chunk in pd.read_csv(file_path, chunksize=self.chunk_size):
                yield chunk
        except Exception as e:
            logger.error(f"Error streaming CSV: {e}")
            raise

    def validate_and_parse(self, df: pd.DataFrame) -> pd.DataFrame:
        """Validate and parse each record"""
